# 代码与公式展示

这是一个用于展示代码片段和数学公式的页面，使用安知鱼主题自带的代码高亮样式。

<!-- 引入 Font Awesome 图标库 -->
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">

<!-- 引入 MathJax 用于渲染数学公式 -->
<script>
  window.MathJax = {
    tex: {
      inlineMath: [['$', '$'], ['\\(', '\\)']],
      displayMath: [['$$', '$$'], ['\\[', '\\]']],
      processEscapes: true,
      processEnvironments: true
    },
    options: {
      skipHtmlTags: ['script', 'noscript', 'style', 'textarea', 'pre', 'code']
    }
  };
</script>
<script id="MathJax-script" async src="https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js"></script>

<!-- 数学公式渲染脚本 -->
<script>
  document.addEventListener('DOMContentLoaded', function() {
    const formulaSection = document.querySelector('.math-formula-section');
    if (formulaSection && window.MathJax && MathJax.typesetPromise) {
      setTimeout(() => {
        MathJax.typesetPromise([formulaSection]).then(() => {
          console.log('数学公式渲染完成');
        }).catch(err => console.log('数学公式渲染失败:', err));
      }, 500);
    }

    // 添加平滑滚动效果
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
      anchor.addEventListener('click', function (e) {
        e.preventDefault();
        const targetId = this.getAttribute('href');
        const targetElement = document.querySelector(targetId);
        if (targetElement) {
          // 计算目标位置并平滑滚动
          const offsetTop = targetElement.offsetTop - 100; // 减去头部导航的高度
          window.scrollTo({
            top: offsetTop,
            behavior: 'smooth'
          });

          // 更新 URL hash（但不立即跳转）
          history.pushState(null, null, targetId);
        }
      });
    });
  });
</script>

## 代码示例

### Python - 快速排序

```python
# Python 示例：快速排序算法
def quick_sort(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return quick_sort(left) + middle + quick_sort(right)
```

### C++ - 矩阵乘法

```cpp
#include <iostream>
#include <vector>

using namespace std;

// 矩阵乘法
vector<vector<int>> matrixMultiply(
    const vector<vector<int>>& A,
    const vector<vector<int>>& B
) {
    int n = A.size();
    int m = B[0].size();
    int k = B.size();
    vector<vector<int>> C(n, vector<int>(m, 0));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            for (int p = 0; p < k; ++p) {
                C[i][j] += A[i][p] * B[p][j];
            }
        }
    }
    return C;
}
```

### Python - 机器学习

```python
# 机器学习示例：线性回归
import numpy as np

class LinearRegression:
    """线性回归模型"""

    def __init__(self, learning_rate=0.01, n_iterations=1000):
        self.learning_rate = learning_rate
        self.n_iterations = n_iterations
        self.weights = None
        self.bias = None

    def fit(self, X, y):
        """训练模型"""
        n_samples, n_features = X.shape
        self.weights = np.zeros(n_features)
        self.bias = 0

        for _ in range(self.n_iterations):
            y_pred = np.dot(X, self.weights) + self.bias
            dw = (1 / n_samples) * np.dot(X.T, (y_pred - y))
            db = (1 / n_samples) * np.sum(y_pred - y)
            self.weights -= self.learning_rate * dw
            self.bias -= self.learning_rate * db

    def predict(self, X):
        """预测"""
        return np.dot(X, self.weights) + self.bias
```

