    // 线框模式按钮
    document.getElementById('toggle-wireframe').addEventListener('click', function() {
      if (mesh) {
        mesh.material.wireframe = !mesh.material.wireframe;
        this.textContent = mesh.material.wireframe ? '实体模式' : '线框模式';
      }
