    if (searchBtn) {
      searchBtn.addEventListener('click', performSearch);
    }

    const questionInput = document.getElementById('question-input');
    if (questionInput) {
      questionInput.addEventListener('keydown', function(e) {
        if (e.ctrlKey && e.key === 'Enter') {
          performSearch();
        }
      });
