// PPT 轮播脚本
let slideIndex = 1;
let slideInterval;

// 初始化轮播
function initCarousel() {
  showSlides(slideIndex);
  startAutoSlide();

  // 添加键盘控制
  document.addEventListener('keydown', function(e) {
    if (e.key === 'ArrowLeft') {
      plusSlides(-1);
    } else if (e.key === 'ArrowRight') {
      plusSlides(1);
    }
  });

  // 添加触摸支持
  let touchStartX = 0;
  let touchEndX = 0;

  document.querySelector('.ppt-container').addEventListener('touchstart', function(e) {
    touchStartX = e.changedTouches[0].screenX;
  }, false);

  document.querySelector('.ppt-container').addEventListener('touchend', function(e) {
    touchEndX = e.changedTouches[0].screenX;
    handleSwipe();
  }, false);

  function handleSwipe() {
    if (touchEndX < touchStartX - 50) {
      plusSlides(1); // 向左滑动
    } else if (touchEndX > touchStartX + 50) {
      plusSlides(-1); // 向右滑动
    }
  }
}

// 切换幻灯片
function plusSlides(n) {
  showSlides(slideIndex += n);
  resetAutoSlide();
}

// 跳转到指定幻灯片
function currentSlide(n) {
  showSlides(slideIndex = n);
  resetAutoSlide();
}

// 显示幻灯片
function showSlides(n) {
  let i;
  let slides = document.getElementsByClassName("ppt-slide");
  let dots = document.getElementsByClassName("ppt-dot");

  if (n > slides.length) {
    slideIndex = 1;
  }
  if (n < 1) {
    slideIndex = slides.length;
  }

  // 显示所有幻灯片（用于轮播切换）
  for (i = 0; i < slides.length; i++) {
    slides[i].style.display = "flex";
  }

  // 移除所有指示器的 active 类
  for (i = 0; i < dots.length; i++) {
    dots[i].className = dots[i].className.replace(" active", "");
  }

  // 激活当前指示器
  dots[slideIndex - 1].className += " active";

  // 更新轮播位置
  document.querySelector('.ppt-slides').style.transform = `translateX(-${(slideIndex - 1) * 100}%)`;

  // 触发懒加载图片
  setTimeout(function() {
    let currentSlide = slides[slideIndex - 1];
    let img = currentSlide.querySelector('img');
    if (img && img.getAttribute('data-lazy-src')) {
      img.src = img.getAttribute('data-lazy-src');
      img.removeAttribute('data-lazy-src');
    }
  }, 100);
}

// 开始自动播放
function startAutoSlide() {
  slideInterval = setInterval(function() {
    plusSlides(1);
  }, 5000); // 每5秒切换一次
}

// 重置自动播放
function resetAutoSlide() {
  clearInterval(slideInterval);
  startAutoSlide();
}

// 处理容器点击事件
function handleContainerClick(event) {
  // 阻止事件冒泡，避免点击图片时触发容器点击
  event.stopPropagation();
}

// 页面加载完成后初始化
window.onload = initCarousel;
</script>

